<?php
declare(strict_types=1);
require __DIR__.'/bootstrap.php';
$customer=vp3_require_customer();$id=(int)vp3_input('id');$row=null;$ready=false;
if(vp3_db_available()){
    try{$ready=(bool)vp3_db()->query("SHOW TABLES LIKE 'project_briefs'")->fetchColumn();}catch(Throwable){}
}
if($ready&&$id>0){$stmt=vp3_db()->prepare('SELECT * FROM project_briefs WHERE id=? AND customer_id=?');$stmt->execute([$id,$customer['id']]);$row=$stmt->fetch();if(!$row){http_response_code(404);exit('Brief not found.');}}
if(vp3_method()==='POST'){
    vp3_verify_csrf();if(!$ready){vp3_flash('error','Import the sales and creative operations migration first.');vp3_redirect('account-project-brief.php');}
    $projectName=vp3_input('project_name');$concept=vp3_input('concept_summary');$action=vp3_input('action','save');
    if($projectName===''||vp3_text_length($concept)<20){vp3_flash('error','Project name and a meaningful concept summary are required.');vp3_redirect('account-project-brief.php'.($id?'?id='.$id:''));}
    $formats=array_values(array_filter(array_map('trim',(array)($_POST['content_formats']??[]))));$services=array_values(array_filter(array_map('trim',(array)($_POST['creative_services']??[]))));
    $status=$action==='submit'?'submitted':'draft';$uuid=(string)($row['brief_uuid']??vp3_uuid());
    $data=[$projectName,vp3_input('brand_name'),$concept,vp3_input('audience_summary'),json_encode($formats,JSON_THROW_ON_ERROR),vp3_input('existing_assets_summary'),vp3_input('launch_goals'),vp3_input('target_launch_date'),vp3_input('hosting_preference','undecided'),json_encode($services,JSON_THROW_ON_ERROR),vp3_input('collaborators_summary'),vp3_input('references_summary'),$status];
    if($id>0){$stmt=vp3_db()->prepare("UPDATE project_briefs SET project_name=?,brand_name=NULLIF(?,''),concept_summary=?,audience_summary=?,content_formats_json=?,existing_assets_summary=?,launch_goals=?,target_launch_date=NULLIF(?,''),hosting_preference=?,creative_services_json=?,collaborators_summary=?,references_summary=?,status=?,submitted_at=CASE WHEN ?='submitted' THEN COALESCE(submitted_at,NOW()) ELSE submitted_at END,updated_at=NOW() WHERE id=? AND customer_id=? AND status IN ('draft','revision_requested')");$stmt->execute([...$data,$status,$id,$customer['id']]);if($stmt->rowCount()!==1){vp3_flash('error','This brief is locked or no longer available for editing.');vp3_redirect('account-project-brief.php?id='.$id);}}
    else{$stmt=vp3_db()->prepare("INSERT INTO project_briefs (brief_uuid,customer_id,project_name,brand_name,concept_summary,audience_summary,content_formats_json,existing_assets_summary,launch_goals,target_launch_date,hosting_preference,creative_services_json,collaborators_summary,references_summary,status,submitted_at,created_at,updated_at) VALUES (?,?,?,NULLIF(?,''),?,?,?,?,?,NULLIF(?,''),?,?,?,?,?,CASE WHEN ?='submitted' THEN NOW() ELSE NULL END,NOW(),NOW())");$stmt->execute([$uuid,$customer['id'],...$data,$status]);$id=(int)vp3_db()->lastInsertId();}
    vp3_audit('customer',(int)$customer['id'],'project_brief.'.$status,'project_brief',$uuid,['id'=>$id]);vp3_flash('success',$status==='submitted'?'Project brief submitted for VP3 review.':'Project brief saved.');vp3_redirect('account-project-brief.php?id='.$id);
}
$pageTitle=$row?'Project Brief':'Start a Project Brief';require VP3_ROOT.'/includes/account-header.php';
$formatsSelected=json_decode((string)($row['content_formats_json']??'[]'),true)?:[];$servicesSelected=json_decode((string)($row['creative_services_json']??'[]'),true)?:[];
?>
<div class="page-head"><div><span class="eyebrow">Creative onboarding</span><h1><?=vp3_e($pageTitle)?></h1><p class="helper">Turn your idea into a structured starting point for discovery, proposal planning, and production.</p></div><a class="button small secondary" href="account-projects.php">Project dashboard</a></div>
<?php if(!$ready):?><div class="notice">Import <code>database/migrations/20260711_sales_creative_operations_v1.sql</code> to enable project onboarding.</div><?php elseif($row && !in_array($row['status'],['draft','revision_requested'],true)):?><div class="notice">This brief is <?=vp3_e($row['status'])?> and is now read-only. VP3 will use it for proposal and project planning.</div><?php else:?><form class="card admin-form" method="post"><?=vp3_csrf_field()?><div class="admin-form-grid"><div class="field"><label>Project name</label><input name="project_name" required value="<?=vp3_e($row['project_name']??'')?>"></div><div class="field"><label>Brand, creator, or show name</label><input name="brand_name" value="<?=vp3_e($row['brand_name']??'')?>"></div><div class="field full"><label>Concept summary</label><textarea name="concept_summary" minlength="20" required><?=vp3_e($row['concept_summary']??'')?></textarea></div><div class="field full"><label>Who is the audience?</label><textarea name="audience_summary"><?=vp3_e($row['audience_summary']??'')?></textarea></div><div class="field full"><label>Content formats</label><div class="check-grid"><?php foreach(['Series / episodes','Music / releases','Short-form clips','Podcast / audio','Membership content','Merchandise','Live events','Editorial / blog'] as $value):?><label class="check-row"><input type="checkbox" name="content_formats[]" value="<?=vp3_e($value)?>" <?=in_array($value,$formatsSelected,true)?'checked':''?>> <?=vp3_e($value)?></label><?php endforeach;?></div></div><div class="field full"><label>Existing assets</label><textarea name="existing_assets_summary"><?=vp3_e($row['existing_assets_summary']??'')?></textarea></div><div class="field full"><label>Launch goals</label><textarea name="launch_goals"><?=vp3_e($row['launch_goals']??'')?></textarea></div><div class="field"><label>Target launch date</label><input type="date" name="target_launch_date" value="<?=vp3_e($row['target_launch_date']??'')?>"></div><div class="field"><label>Hosting preference</label><select name="hosting_preference"><?php foreach(['undecided'=>'Undecided','self_hosted'=>'Self-hosted','vp3_hosted'=>'VP3 hosted','enterprise'=>'Enterprise'] as $value=>$label):?><option value="<?=$value?>" <?=($row['hosting_preference']??'undecided')===$value?'selected':''?>><?=$label?></option><?php endforeach;?></select></div><div class="field full"><label>Creative services needed</label><div class="check-grid"><?php foreach(['Story development','Content writing','Production planning','Platform setup','Brand implementation','Catalog migration','Launch campaign','Ongoing creative operations'] as $value):?><label class="check-row"><input type="checkbox" name="creative_services[]" value="<?=vp3_e($value)?>" <?=in_array($value,$servicesSelected,true)?'checked':''?>> <?=vp3_e($value)?></label><?php endforeach;?></div></div><div class="field full"><label>Collaborators and team</label><textarea name="collaborators_summary"><?=vp3_e($row['collaborators_summary']??'')?></textarea></div><div class="field full"><label>References, inspiration, or links</label><textarea name="references_summary"><?=vp3_e($row['references_summary']??'')?></textarea></div></div><div class="form-actions"><button class="button secondary" name="action" value="save">Save draft</button><button class="button" name="action" value="submit">Submit for review</button></div></form><?php endif;?>
<?php require VP3_ROOT.'/includes/account-footer.php'; ?>
